// Devuelve los escalados. Por defecto oculta los soft-deleted; con
// ?incluir_archivados=1 los incluye al final del orden. Filtros opcionales:
//   ?ficha_id=<uuid>      sólo escalados de un cliente
//   ?tipo=modulo|local
//   ?estado=pendiente|aplicado|cancelado
//   ?incluir_archivados=1
const wh = $('Webhook GET Escalados').first().json || {};
const q  = wh.query || wh.params || {};
const verArch = String(q.incluir_archivados || '') === '1';
let out = ($input.all() || [])
  .map(i => i.json)
  .filter(x => x && x.id && (verArch || !x.deleted_at));

if (q.ficha_id) out = out.filter(e => e.ficha_id === q.ficha_id);
if (q.tipo)     out = out.filter(e => e.tipo === q.tipo);
if (q.estado)   out = out.filter(e => e.estado === q.estado);

// Orden: vivos primero (no archivados); dentro, pendientes antes que el resto
// y por fecha de creación descendente.
const pesoEstado = { pendiente: 0, aplicado: 1, cancelado: 2 };
out.sort((a, b) => {
  const ax = a.deleted_at ? 1 : 0;
  const bx = b.deleted_at ? 1 : 0;
  if (ax !== bx) return ax - bx;
  const pa = pesoEstado[a.estado] ?? 9;
  const pb = pesoEstado[b.estado] ?? 9;
  if (pa !== pb) return pa - pb;
  const da = a.created_at ? new Date(a.created_at).getTime() : 0;
  const db = b.created_at ? new Date(b.created_at).getTime() : 0;
  return db - da;
});

// Totales agregados (sólo vivos no cancelados): cuántos hay y suma de
// recurrencia. Útil para que el front muestre KPIs sin recalcular.
const totales = out
  .filter(e => !e.deleted_at && e.estado !== 'cancelado')
  .reduce((acc, e) => {
    acc.count       += 1;
    acc.setup       += Number(e.setup)       || 0;
    acc.recurrencia += Number(e.recurrencia) || 0;
    return acc;
  }, { count: 0, setup: 0, recurrencia: 0 });

return [{ json: { escalados: out, totales } }];

// Acciones soportadas:
//   create   → alta de escalado en estado 'pendiente' (default si no llega action)
//   update   → edición de detalle/importes/notas
//   aplicar  → marca como aplicado y setea aplicado_at = now()
//             (NO aplica todavía los cambios reales sobre fichas/locales —
//              eso lo hará un workflow posterior, ver flujo de aplicación)
//   cancelar → estado='cancelado'
//   archivar / reactivar → soft-delete
//
// Acepta el payload tanto envuelto en { escalado: {...}, action } como
// plano (todo en raíz). Cuando llega plano sin action lo tratamos como
// 'create' — es lo que envía la página escalados.html actual.
const raw  = $input.first().json || {};
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const e    = (body.escalado && typeof body.escalado === 'object') ? body.escalado : body;
const action = String(body.action || (e.id ? 'update' : 'create')).toLowerCase();
const now = new Date().toISOString();
const errores = [];

const VALID = ['create', 'update', 'aplicar', 'cancelar', 'archivar', 'reactivar'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !e.id) errores.push('id obligatorio para ' + action);
if (e.id && !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(e.id)) {
  errores.push('id no es un UUID válido');
}

const TIPOS    = ['modulo', 'local'];
const ESTADOS  = ['pendiente', 'aplicado', 'cancelado'];

function validaNumero(v, nombre, min, max) {
  if (v === undefined || v === null || v === '') return undefined;
  const n = +v;
  if (!Number.isFinite(n))    { errores.push(nombre + ' debe ser número'); return undefined; }
  if (n < min || n > max)      { errores.push(nombre + ' fuera de rango (' + min + '..' + max + ')'); return undefined; }
  return n;
}

function validaDetalle(tipo, det) {
  if (!det || typeof det !== 'object') { errores.push('detalle debe ser objeto'); return; }
  if (tipo === 'modulo') {
    if (!Array.isArray(det.modulos) || det.modulos.length === 0)
      errores.push('detalle.modulos debe ser array no vacío');
    if (!Array.isArray(det.locales_ids) || det.locales_ids.length === 0)
      errores.push('detalle.locales_ids debe ser array no vacío');
  } else if (tipo === 'local') {
    if (!det.local || typeof det.local !== 'object' || !String(det.local.nombre || '').trim())
      errores.push('detalle.local.nombre obligatorio');
    const sepa = det.sepa || {};
    if (!['existente','nuevo'].includes(sepa.modo))
      errores.push('detalle.sepa.modo debe ser existente|nuevo');
    if (sepa.modo === 'existente' && !sepa.mandato_id)
      errores.push('detalle.sepa.mandato_id obligatorio cuando modo=existente');
    if (sepa.modo === 'nuevo' && !String(sepa.iban || '').trim())
      errores.push('detalle.sepa.iban obligatorio cuando modo=nuevo');
  }
}

let out = {};
if (action === 'create') {
  if (!e.ficha_id) errores.push('ficha_id obligatorio');
  else if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(e.ficha_id))
    errores.push('ficha_id no es UUID válido');
  if (!TIPOS.includes(e.tipo)) errores.push('tipo debe ser modulo|local');
  if (e.estado && !ESTADOS.includes(e.estado)) errores.push('estado debe ser pendiente|aplicado|cancelado');
  validaDetalle(e.tipo, e.detalle);
  const setup = validaNumero(e.setup,       'setup',       0, 99999999.99);
  const recur = validaNumero(e.recurrencia, 'recurrencia', 0, 99999999.99);
  const _uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16); });
  out = {
    id: _uuid,
    ficha_id: e.ficha_id,
    tipo: e.tipo,
    estado: e.estado || 'pendiente',
    detalle: e.detalle || {},
    setup:       setup !== undefined ? setup : 0,
    recurrencia: recur !== undefined ? recur : 0,
    creado_por: e.creado_por != null ? String(e.creado_por) : null,
    notas:      e.notas      != null ? String(e.notas)      : null,
    created_at: now,
    updated_at: now
  };
} else if (action === 'update') {
  out.id = e.id;
  if (e.tipo !== undefined) {
    if (!TIPOS.includes(e.tipo)) errores.push('tipo debe ser modulo|local');
    else out.tipo = e.tipo;
  }
  if (e.estado !== undefined) {
    if (!ESTADOS.includes(e.estado)) errores.push('estado debe ser pendiente|aplicado|cancelado');
    else out.estado = e.estado;
  }
  if (e.detalle !== undefined) {
    validaDetalle(e.tipo || (out.tipo || ''), e.detalle);
    out.detalle = e.detalle;
  }
  if (e.setup       !== undefined) { const n = validaNumero(e.setup,       'setup',       0, 99999999.99); if (n !== undefined) out.setup       = n; }
  if (e.recurrencia !== undefined) { const n = validaNumero(e.recurrencia, 'recurrencia', 0, 99999999.99); if (n !== undefined) out.recurrencia = n; }
  if (e.notas       !== undefined) out.notas       = e.notas       != null ? String(e.notas)       : null;
  if (e.creado_por  !== undefined) out.creado_por  = e.creado_por  != null ? String(e.creado_por)  : null;
  out.updated_at = now;
} else if (action === 'aplicar') {
  out = { id: e.id, estado: 'aplicado', aplicado_at: now, updated_at: now };
} else if (action === 'cancelar') {
  out = { id: e.id, estado: 'cancelado', updated_at: now };
} else if (action === 'archivar') {
  out = { id: e.id, deleted_at: now, updated_at: now };
} else if (action === 'reactivar') {
  out = { id: e.id, deleted_at: null, updated_at: now };
}

Object.keys(out).forEach(k => { if (out[k] === undefined) delete out[k]; });

if (errores.length > 0) {
  return [{ json: { __error: true, __errores: errores, __action: action, __method: 'POST', __qs: 'on_conflict=id' } }];
}
const _method = (action === 'create') ? 'POST' : 'PATCH';
const _qs     = (action === 'create') ? 'on_conflict=id' : ('id=eq.' + encodeURIComponent(e.id || ''));
return [{ json: Object.assign({}, out, { __method: _method, __qs: _qs, __action: action }) }];

// Normaliza la salida PostgREST al shape único del frontend:
//   { success, escalado, errores }
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, escalado: null, errores: prep.__errores || ['validación falló'] } }];
}
const items = $input.all() || [];
const errores = [];
let rows = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.code && j.message && !j.id) {
    errores.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
    continue;
  }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.id) rows.push(j);
  if (Array.isArray(j.data)) rows = rows.concat(j.data);
}
if (rows.length === 0 && errores.length === 0) errores.push('PostgREST devolvió 0 filas');
return [{ json: {
  success: rows.length > 0,
  escalado: rows[0] || null,
  errores
} }];
